export default function SummaryCard({ title, time, summary, variant = "bert" }) {
    return (
        <div className="summary-card">
            <div className={`summary-card-header ${variant}-header`}>
                <span>📄 {title}</span>
                <span className={`time-chip ${variant}`}>{time?.toFixed(3)}s</span>
            </div>
            <div className="summary-body">
                {summary}
            </div>
        </div>
    );
}
